import unittest

class TestSolution(unittest.TestCase):
    def test_basic_example(self):
        self.assertEqual(balance_history(1000, [200, -150, 300, -500]), [1200, 1050, 1350, 850])

    def test_all_deposits(self):
        self.assertEqual(balance_history(0, [100, 200, 300]), [100, 300, 600])

    def test_single_transaction(self):
        self.assertEqual(balance_history(100, [50]), [150])

    def test_hidden_empty_transactions(self):
        self.assertEqual(balance_history(500, []), [])

    def test_hidden_all_withdrawals(self):
        self.assertEqual(balance_history(1000, [-100, -200, -300]), [900, 700, 400])

    def test_hidden_goes_negative(self):
        self.assertEqual(balance_history(100, [-200]), [-100])

    def test_hidden_zero_transactions(self):
        self.assertEqual(balance_history(0, [0, 0, 0]), [0, 0, 0])

    def test_hidden_large_values(self):
        self.assertEqual(balance_history(1000000, [500000, -750000]), [1500000, 750000])

    def test_hidden_mixed_sign_zero_start(self):
        self.assertEqual(balance_history(0, [50, -30, 20, -40]), [50, 20, 40, 0])

if __name__ == '__main__':
    unittest.main()
